import { forwardRef } from "react";
import {
  RadioButton,
  type RadioButtonProps,
  type RadioButtonLabel,
} from "../RadioButton";
import { ToggleTile } from "../ToggleTile";
import type { RadioButtonTileSize } from "./RadioButtonTile.config";
import { DEFAULT_RADIO_BUTTON_TILE_SIZE } from "./RadioButtonTile.config";
import { useRadioGroupContext } from "../RadioGroup";

export type RadioButtonTileLabel = Omit<RadioButtonLabel, "asChild">;

interface RadioButtonTileCustomProps {
  /**
   * The size of the tile, which controls the padding.
   * @default 'lg'
   */
  size?: RadioButtonTileSize;

  /**
   * The visible label configuration for the tile (asChild is controlled internally).
   */
  label: RadioButtonTileLabel;

  /**
   * Additional CSS class name(s) to apply to the tile container.
   */
  className?: string;
}

export interface RadioButtonTileProps
  extends
    Omit<RadioButtonProps, keyof RadioButtonTileCustomProps>,
    RadioButtonTileCustomProps {}

/**
 * A tile-styled radio button component that allows clicking anywhere on the tile to select.
 * The entire tile is wrapped in a label element for full click area coverage.
 * The input's accessible name comes from aria-labelledby (pointing to the visible label text),
 * not from the wrapping label element (which would include the hint text).
 */
export const RadioButtonTile = forwardRef<
  HTMLLabelElement,
  RadioButtonTileProps
>(
  (
    {
      size = DEFAULT_RADIO_BUTTON_TILE_SIZE,
      className,
      disabled = false,
      ...radioButtonProps
    },
    ref
  ) => {
    // Get radio group state from context (provided by RadioGroup)
    const groupState = useRadioGroupContext();

    // Derive checked, error, and disabled state from the RadioGroup context
    const isChecked = groupState.selectedValue === radioButtonProps.value;
    const hasError = groupState.isInvalid;
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || groupState.isDisabled;

    return (
      <ToggleTile
        ref={ref}
        size={size}
        checked={isChecked}
        disabled={isDisabled}
        invalid={hasError}
        className={className}
      >
        <RadioButton {...radioButtonProps} disabled={disabled} hideFocusRing />
      </ToggleTile>
    );
  }
);

RadioButtonTile.displayName = "RadioButtonTile";
